import React, { useState } from 'react';
import Sidebar from '../components/Sidebar';
import './CadastroProduto.css';

const CadastroProduto = () => {
  const [formData, setFormData] = useState({
    nome: '',
    preco: '',
    categoria: 'cigarro',
    img: ''
  });

  const [mensagem, setMensagem] = useState('');

  const categorias = [
    { value: 'cigarro', label: 'Cigarros' },
    { value: 'bebida', label: 'Bebidas' },
    { value: 'tabacaria', label: 'Tabacaria' },
    { value: 'carta', label: 'Cartas' },
    { value: 'acessorio', label: 'Acessórios' }
  ];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    // Validação básica
    if (!formData.nome || !formData.preco || !formData.categoria) {
      setMensagem('Por favor, preencha todos os campos obrigatórios!');
      return;
    }

    // Simulação de salvamento (em um app real, isso iria para uma API)
    const produtosSalvos = JSON.parse(localStorage.getItem('produtos_adicionados') || '[]');
    const novoProduto = {
      ...formData,
      preco: parseFloat(formData.preco),
      img: formData.img || '/images/generic-product.svg',
      id: Date.now()
    };

    produtosSalvos.push(novoProduto);
    localStorage.setItem('produtos_adicionados', JSON.stringify(produtosSalvos));

    setMensagem('Produto cadastrado com sucesso!');
    setFormData({
      nome: '',
      preco: '',
      categoria: 'cigarro',
      img: ''
    });

    // Limpar mensagem após 3 segundos
    setTimeout(() => setMensagem(''), 3000);
  };

  return (
    <div>
      <Sidebar />
      <div className="cadastro-container">
        <div className="cadastro-header">
          <h1>Cadastrar Produto</h1>
          <p>Adicione novos produtos ao catálogo</p>
        </div>

        {mensagem && (
          <div className={`mensagem ${mensagem.includes('sucesso') ? 'sucesso' : 'erro'}`}>
            {mensagem}
          </div>
        )}

        <form className="cadastro-form" onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="nome">Nome do Produto *</label>
            <input
              type="text"
              id="nome"
              name="nome"
              value={formData.nome}
              onChange={handleChange}
              placeholder="Ex: Coca-Cola Lata"
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="preco">Preço (R$) *</label>
            <input
              type="number"
              id="preco"
              name="preco"
              value={formData.preco}
              onChange={handleChange}
              placeholder="Ex: 8.50"
              step="0.01"
              min="0"
              required
            />
          </div>

          <div className="form-group">
            <label htmlFor="categoria">Categoria *</label>
            <select
              id="categoria"
              name="categoria"
              value={formData.categoria}
              onChange={handleChange}
              required
            >
              {categorias.map(cat => (
                <option key={cat.value} value={cat.value}>
                  {cat.label}
                </option>
              ))}
            </select>
          </div>

          <div className="form-group">
            <label htmlFor="img">URL da Imagem (opcional)</label>
            <input
              type="text"
              id="img"
              name="img"
              value={formData.img}
              onChange={handleChange}
              placeholder="Deixe em branco para usar imagem genérica"
            />
          </div>

          <button type="submit" className="btn-cadastrar">
            Cadastrar Produto
          </button>
        </form>

        <div className="produtos-cadastrados">
          <h2>Produtos Cadastrados</h2>
          <p>Estes são os produtos adicionados por você:</p>
          {/* Aqui você pode listar os produtos cadastrados se desejar */}
        </div>
      </div>
    </div>
  );
};

export default CadastroProduto;
